import{_ as l}from"./Menu.edeb1320.js";import{u as n}from"./composables.4a9b2b71.js";import{r as t,a as r,e,b as o,f as u,o as c}from"./entry.787c95cd.js";const d=""+new URL("bluecake-iv.6843cd8c.png",import.meta.url).href,p=""+new URL("charlotte-aux-fraises.6a6c8f86.jpg",import.meta.url).href,m={class:"banniere"},v=u('<div class="margium-l marge-haute-l"><div class="espacium"><h1>BlueCake</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet libre,<br> 2015 \xE0 2016 - 2020 \xE0 2022 </div><div class="colonne"><div class="projettitre">Savoir-faire</div> Gestion de projet, UI design, tournage, montage vid\xE9o </div><div class="colonne"><div class="projettitre">\xC9quipe</div><a href="https://fr.linkedin.com/in/martin-lorgnier" target="_blank">Martin Lorgnier</a></div><div class="colonne"><a href="https://bluecakecuisine.fr" class="lienapp" target="_blank">Voir le site web</a></div></div></div></div>',1),f=e("article",{class:"margium-l marge-haute-l marge-basse-l"},[e("div",{class:"espacium"},[e("div",{class:"coldroite"},[e("p",null,"BlueCake ou BlueCake cuisine est une cha\xEEne YouTube et un site web de recettes de cuisine. Cr\xE9\xE9 en 2015, elle a produit 40 vid\xE9os entre 2015 et 2016. En 2021, le projet est relanc\xE9 par une nouvelle saison de vid\xE9o avec un montage vid\xE9o plus moderne et facilitant. L'ann\xE9e qui a suivi a fait l'objet d'une nouvelle identit\xE9 graphique, d'un nouveau site web. La cha\xEEne a atteint les 10k abonn\xE9es avec plus de 1.9 Million de vues."),e("h2",null,"Les vid\xE9os"),e("div",{class:"container"},[e("iframe",{class:"video",width:"720",height:"405",src:"https://www.youtube-nocookie.com/embed/X7RQXlOEnRQ",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture",allowfullscreen:""})]),e("p",null," Les vid\xE9os de la cha\xEEne sont mont\xE9es de mani\xE8re \xE0 \xEAtre courtes pour \xEAtre davantage choisies sur la liste de r\xE9sultats YouTube et d'aller \xE0 l'essentiel dans la pr\xE9sentation de la recette. Les plans sont coup\xE9s en \xABjump cut\xBB, et accompagn\xE9s d'une voix et d'un bandeau sous-titr\xE9 pour s'adapter aux multiples conditions de lecture. Les images sont film\xE9es au Canon EOS 200D et mont\xE9es sur Olive Editor 0.2.0. "),e("h2",null,"Identit\xE9 Visuelle"),e("img",{src:d,alt:"identit\xE9 visuelle de Bluecake : logo, couleurs, formes et jeux typographique"}),e("p",null," La pr\xE9c\xE9dente identit\xE9 visuelle \xE9tait trop corporate, avec une palette r\xE9duite et une police script peu lisible. L'objectif de la refonte \xE9tait de rendre les diff\xE9rents supports de BlueCake plus amicaux et identifiables. Le logo a \xE9t\xE9 con\xE7u \xE0 la main pour un aspect plus enfantin et singulier. Les couleurs sont tr\xE8s contrast\xE9es sont chaleureuses : le bleu myrtille et tr\xE8s sombre et les couleurs rose et bleu sont tr\xE8s saillantes pour guider le regard des utilisateurs dans l'interface. La police Poppins a remplac\xE9 la police Pacifico qui \xE9tait plus complexe \xE0 lire. "),e("h2",null,"Site web"),e("p",null,"Le site web a \xE9t\xE9 enti\xE8rement refondu. Les maquettes, on \xE9tait r\xE9alis\xE9 sur Figma en mobile first, 80% du trafic s'effectue sur un terminal mobile. Le d\xE9veloppement s'est effectu\xE9 sur un WordPress pour faciliter les ajouts de recettes."),e("img",{src:p,loading:"lazy",alt:"Capture d'\xE9cran de la page recette de charlotte aux fraises"})])])],-1),w={__name:"bluecake",setup(b){const s=t("BlueCake - Lucas Lacroix"),a=t("BlueCake cuisine est une cha\xEEne YouTube et un site web de recettes de cuisine. Cr\xE9\xE9 en 2015, elle a produit 40 vid\xE9os entre 2015 et 2016. En 2021");return n({title:s,meta:[{name:"description",content:a}]}),(g,h)=>{const i=l;return c(),r("div",null,[e("div",m,[o(i),v]),f])}}};export{w as default};
